#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline ll read(){
    ll x=0ll,f=1ll;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1ll;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10ll+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
int t;
ll n;
int main(void)
{
	for(t=read();t--;)
	{
		n=read();
		for(ll i=2;;++i)
		{
			if(n%i==0)
			{
				ll j=sqrtl(n/i);
				if(j*j==n/i)
				{
					write(j);
					putchar(' ');
					write(i);
					puts(""); 
				}	
				else
				{
					write(i);
					putchar(' ');
					write(n/i/i);
					puts(""); 
				}
				break;
			}
		}	
	}
	return false;
}
